select count(*) from postgres.votes as v, postgres.posts as p, postgres.badges as b, postgres.users as u where p.id = v.postid and u.id = p.owneruserid and u.id = b.userid and v.creationdate<=timestamp '2014-09-12 00:00:00' and p.posttypeid=1 and p.score>=-1 and p.favoritecount>=0 and p.favoritecount<=20 and b."date">=timestamp '2010-07-20 19:02:22' and b.date<=timestamp '2014-09-03 23:36:09' and u.downvotes<=2 and u.upvotes>=0 and u.creationdate>=timestamp '2010-11-26 03:34:11';
